const { geo, geoFromHeaders, isInRegion, geoDistance, COUNTRY_NAMES } = require('./packages/next/src/server/web/spec-extension/geo.ts');

let passed = 0;
let failed = 0;
function assert(condition, msg) {
  if (condition) { passed++; console.log('  PASS:', msg); }
  else { failed++; console.error('  FAIL:', msg); }
}

// Test 1: geo() with Vercel headers
console.log('\\nTest: geo() with Vercel headers');
const h1 = new Headers({
  'x-vercel-ip-city': 'New York',
  'x-vercel-ip-country': 'US',
  'x-vercel-ip-country-region': 'NY',
  'x-vercel-ip-latitude': '40.7128',
  'x-vercel-ip-longitude': '-74.0060',
  'x-vercel-ip-timezone': 'America/New_York',
});
const r1 = geo({ headers: h1 });
assert(r1.city === 'New York', 'city = New York');
assert(r1.countryCode === 'US', 'countryCode = US');
assert(r1.country === 'United States', 'country = United States');
assert(r1.region === 'NY', 'region = NY');
assert(r1.latitude === '40.7128', 'latitude');
assert(r1.longitude === '-74.0060', 'longitude');
assert(r1.timezone === 'America/New_York', 'timezone');

// Test 2: missing headers
console.log('\\nTest: missing headers -> undefined');
const r2 = geo({ headers: new Headers() });
assert(r2.city === undefined, 'city undefined');
assert(r2.country === undefined, 'country undefined');
assert(r2.countryCode === undefined, 'countryCode undefined');
assert(r2.region === undefined, 'region undefined');
assert(r2.latitude === undefined, 'latitude undefined');
assert(r2.longitude === undefined, 'longitude undefined');
assert(r2.timezone === undefined, 'timezone undefined');

// Test 3: Cloudflare fallback
console.log('\\nTest: geoFromHeaders() Cloudflare fallback');
const h3 = new Headers({ 'cf-ipcountry': 'DE' });
const r3 = geoFromHeaders(h3);
assert(r3.countryCode === 'DE', 'countryCode = DE from cf-ipcountry');
assert(r3.country === 'Germany', 'country = Germany');

// Test 4: Vercel preferred over Cloudflare
console.log('\\nTest: Vercel header preferred over Cloudflare');
const h4 = new Headers({ 'x-vercel-ip-country': 'US', 'cf-ipcountry': 'DE' });
const r4 = geoFromHeaders(h4);
assert(r4.countryCode === 'US', 'countryCode = US (Vercel wins)');

// Test 5: country name lookup
console.log('\\nTest: country name lookup');
const r5 = geo({ headers: new Headers({ 'x-vercel-ip-country': 'JP' }) });
assert(r5.country === 'Japan', 'JP -> Japan');
const r5b = geo({ headers: new Headers({ 'x-vercel-ip-country': 'XX' }) });
assert(r5b.country === undefined, 'XX -> undefined country');

// Test 6: isInRegion
console.log('\\nTest: isInRegion');
assert(isInRegion({ countryCode: 'US' }, ['US', 'CA']) === true, 'US in [US,CA]');
assert(isInRegion({ countryCode: 'us' }, ['US', 'CA']) === true, 'us (lowercase) in [US,CA]');
assert(isInRegion({ countryCode: 'US' }, ['us', 'ca']) === true, 'US in [us,ca]');
assert(isInRegion({ countryCode: 'US' }, ['GB', 'DE']) === false, 'US not in [GB,DE]');
assert(isInRegion({}, ['US']) === false, 'undefined countryCode -> false');

// Test 7: geoDistance NYC to London
console.log('\\nTest: geoDistance NYC -> London');
const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278');
console.log('  Distance:', dist.toFixed(1), 'km');
assert(Math.abs(dist - 5570) < 50, 'NYC-London ~5570km (got ' + dist.toFixed(1) + ')');

// Test 8: geoDistance identical points
const dist0 = geoDistance('40.7128', '-74.0060', '40.7128', '-74.0060');
assert(dist0 === 0, 'identical points -> 0');

// Test 9: COUNTRY_NAMES
console.log('\\nTest: COUNTRY_NAMES');
assert(Object.keys(COUNTRY_NAMES).length >= 10, 'at least 10 entries');
assert(COUNTRY_NAMES['US'] === 'United States', 'US -> United States');
assert(COUNTRY_NAMES['GB'] === 'United Kingdom', 'GB -> United Kingdom');
assert(COUNTRY_NAMES['JP'] === 'Japan', 'JP -> Japan');

console.log('\\n========================================');
console.log('Results:', passed, 'passed,', failed, 'failed');
if (failed > 0) process.exit(1);
" 2>&1

